// dev-loader.js（极简）
// 用：在酒馆助手里先加载这个文件，它会拉你仓库里最新 bundle
(async () => {
  const BASE = 'https://cdn.jsdelivr.net/gh/RockingSisyphus/ERA-EfficientRollbackArchitecture@master/artifact/bundle.js';
  const url = `${BASE}?dev_ts=${Date.now()}`;    // 强制绕过缓存
  const mod = await import(url);                 // 动态加载最新构建
  // 如果你的库导出卸载/初始化钩子，可选择调用：
  // window.__ERA__?.dispose?.();
  // await mod.init?.();
  return mod;
})();

(() => {
  const url = encodeURI('http://localhost:5500/dist/ApiTest/index.js') + '?v=' + Date.now();
  const s = document.createElement('script');
  s.src = url;
  s.async = false;
  s.onload = () => console.log('《ERA-ApiTest》已加载并执行：', url);
  s.onerror = e => console.error('《ERA-ApiTest》加载失败：', url, e);
  document.head.appendChild(s);
})();

eventOn(tavern_events.MESSAGE_RECEIVED, async message_id => {
  const chat_message = getChatMessages(message_id)[0];
  await setChatMessages([{ message_id, message: chat_message.message.replace(/----------test----------- |$/s, '----------test----------- ') }]);
});

