<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>兰斯全系列决战</title>
    <style>
        @import url('https://fonts.googleapis.com/css2?family=Noto+Serif+SC:wght@700;900&display=swap');

        :root {
            --bg-color: #0b0b0b;
            --panel-bg: rgba(20, 20, 20, 0.9);
            --border-gold: #c0a060;
            --text-main: #e0e0e0;
            --accent-red: #d63031;
            --btn-hover: #ffecb3;
            --font-main: 'Noto Serif SC', serif;
        }

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
            user-select: none;
        }

        body {
            font-family: var(--font-main);
            background-color: var(--bg-color);
            background-image: url('https://s1.imagehub.cc/images/2026/01/21/0084df2d4adcc2023a3507cc5aabea3b.jpg');
            background-size: cover;
            background-position: center;
            background-attachment: fixed;
            color: var(--text-main);
            min-height: 100vh;
            overflow-y: auto;
            padding: 40px 20px;
            display: flex;
            justify-content: center;
            align-items: flex-start;
        }

        body::before {
            content: '';
            position: fixed;
            top: 0; left: 0; width: 100%; height: 100%;
            background: rgba(0, 0, 0, 0.7);
            z-index: -1;
            backdrop-filter: blur(5px);
        }

        /* 主容器 */
        .main-container {
            width: 100%;
            max-width: 1600px;
            background: var(--panel-bg);
            border: 2px solid #555;
            box-shadow: 0 0 50px rgba(0,0,0,0.8);
            border-radius: 8px;
            position: relative;
            height: auto;
            display: flex;
            flex-direction: column;
            margin-bottom: 50px;
        }

        .border-deco {
            position: absolute;
            pointer-events: none;
            border: 2px solid var(--border-gold);
            top: 5px; left: 5px; right: 5px; bottom: 5px;
            z-index: 10;
        }

        .header {
            padding: 40px 20px;
            text-align: center;
            border-bottom: 1px solid rgba(255,255,255,0.1);
            position: relative;
            z-index: 20;
        }
        .header h1 {
            font-size: 3em;
            color: var(--border-gold);
            text-shadow: 0 0 10px rgba(192, 160, 96, 0.5);
            letter-spacing: 5px;
            margin-bottom: 10px;
        }
        .header p {
            margin-bottom: 10px;
            color: #aaa;
            letter-spacing: 1px;
        }

        /* 头部特别按钮样式 */
        .special-start-btn {
            display: inline-block;
            margin-top: 15px;
            padding: 12px 30px;
            background: linear-gradient(90deg, rgba(192, 160, 96, 0.2), rgba(214, 48, 49, 0.2));
            border: 1px solid var(--border-gold);
            color: var(--border-gold);
            font-family: var(--font-main);
            font-size: 1.2em;
            font-weight: bold;
            cursor: pointer;
            border-radius: 50px; /* 圆角设计以示区分 */
            transition: all 0.3s ease;
            box-shadow: 0 0 10px rgba(0,0,0,0.5);
            text-decoration: none;
        }
        .special-start-btn:hover {
            background: var(--border-gold);
            color: #000;
            box-shadow: 0 0 20px var(--border-gold);
            transform: scale(1.05);
        }
        .special-start-btn::after {
            content: ' ▶';
        }

        .scenario-grid {
            padding: 40px;
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
            gap: 30px;
            position: relative;
            z-index: 20;
        }

        /* 卡片样式 */
        .card {
            position: relative;
            height: 480px;
            border: 1px solid #333;
            border-radius: 4px;
            overflow: hidden;
            transition: all 0.4s ease;
            background: #000;
            box-shadow: 0 10px 20px rgba(0,0,0,0.5);
            group: card;
        }

        .card:hover {
            transform: translateY(-5px);
            border-color: var(--border-gold);
            box-shadow: 0 15px 30px rgba(192, 160, 96, 0.3);
            z-index: 30;
        }

        .card-img {
            width: 100%;
            height: 100%;
            object-fit: cover;
            transition: transform 0.6s, filter 0.4s;
            filter: brightness(0.8) grayscale(0.3);
        }
        .card:hover .card-img {
            transform: scale(1.1);
            filter: brightness(1.1) grayscale(0);
        }

        .card-info {
            position: absolute;
            bottom: 0; left: 0; width: 100%;
            background: linear-gradient(to top, rgba(0,0,0,0.98) 10%, rgba(0,0,0,0.9) 60%, transparent 100%);
            padding: 60px 20px 20px 20px;
            display: flex;
            flex-direction: column;
            justify-content: flex-end;
        }

        .series-num {
            position: absolute;
            top: 15px; left: 15px;
            background: rgba(0,0,0,0.8);
            border: 1px solid var(--border-gold);
            color: var(--border-gold);
            padding: 5px 12px;
            font-weight: bold;
            font-size: 0.9em;
            z-index: 5;
        }

        .card-title {
            color: #fff;
            font-size: 1.6em;
            font-weight: 900;
            margin-bottom: 5px;
            text-shadow: 2px 2px 4px #000;
        }

        .card-location {
            color: #bbb;
            font-size: 0.9em;
            margin-bottom: 15px;
            display: flex;
            align-items: center;
            gap: 6px;
        }

        /* 普通启动按钮 */
        .start-btn {
            background: rgba(192, 160, 96, 0.1);
            border: 1px solid var(--border-gold);
            color: var(--border-gold);
            padding: 12px;
            text-align: center;
            font-family: var(--font-main);
            font-weight: bold;
            letter-spacing: 2px;
            cursor: pointer;
            transition: all 0.3s;
            text-transform: uppercase;
            position: relative;
            overflow: hidden;
        }

        .start-btn:hover {
            background: var(--border-gold);
            color: #000;
            box-shadow: 0 0 15px var(--border-gold);
        }

        .start-btn::after {
            content: '▶';
            margin-left: 10px;
            transition: margin-left 0.3s;
        }
        .start-btn:hover::after {
            margin-left: 15px;
        }

        .footer {
            padding: 20px;
            text-align: center;
            border-top: 1px solid rgba(255,255,255,0.1);
            color: #666;
            font-size: 0.8em;
            z-index: 20;
        }

        @media (max-width: 768px) {
            body { padding: 10px; }
            .scenario-grid { grid-template-columns: 1fr; padding: 20px; }
            .card { height: 350px; }
        }
    </style>
</head>
<body>

    <div class="main-container">
        <div class="border-deco"></div>
        <div class="header">
            <h1>RANCE CHRONICLE</h1>
            <p>路得拉萨乌姆全史 · 剧本选择</p>


            <p>作者 · 夜畔十二点</p>


            <p>故事背景</p>

            <p>你是兰斯世界中的主角兰斯，处于一个充满冒险、战争与爱欲的时代。这个世界正面临魔人军团的威胁，英雄与反派、忠诚与背叛、爱情与使命在此交织。你的故事由此展开</p>



            <p>“游玩须知 · 渲染楼层改为2”</p>
            <!-- 特别启动按钮：对应R1 -->
            <div class="special-start-btn" onclick="startGame(1)">
                梦的起点 第一章 寻找小光
            </div>
        </div>

        <div id="grid-container" class="scenario-grid"></div>

        <div class="footer">
            Rance Series Unofficial Portal | System Ver 2.3
        </div>
    </div>

    <script>
        const ranceSeries = [
            { id: 1, title: "寻找小光", location: "利萨斯王国 / 边境", img: "https://s1.imagehub.cc/images/2026/01/21/f1e11a1283fde244a9365ac6f46a9ef3.jpg" },
            { id: 2, title: "反乱的少女", location: "自由都市 / 习俗村", img: "https://s1.imagehub.cc/images/2026/01/21/1eedfa18ebd2446084a252018088ae0a.jpg" },
            { id: 3, title: "利萨斯陷落", location: "利萨斯 / 王城", img: "https://s1.imagehub.cc/images/2026/01/21/c6950305acb1d74dae1c02fd9758ec23.jpg" },
            { id: 4, title: "教团的遗产", location: "浮游都市 / 斗神都市", img: "https://s1.imagehub.cc/images/2026/01/21/d52c985e554122aa5c9521d468df5db3.jpg" },
            { id: 5, title: "孤独的少女", location: "玄武城 / 异世界", img: "https://s1.imagehub.cc/images/2026/01/21/c655aecd1645bf2fdd07056060ff1abc.jpg" },
            { id: 6, title: "赛斯崩坏", location: "魔法大国赛斯", img: "https://s1.imagehub.cc/images/2026/01/21/92fe7ea6141250bc09639c5095ea4eaf.jpg" },
            { id: 7, title: "战国兰斯", location: "JAPAN / 尾张", img: "https://s1.imagehub.cc/images/2026/01/21/bb65d26b9a1267561d816676124e773d.jpg" },
            { id: 8, title: "Quest", location: "世界各地 / 冒险公会", img: "https://s1.imagehub.cc/images/2026/01/21/98527102d628bf59e731f4bb33d3fb5b.jpg" },
            { id: 9, title: "赫尔曼革命", location: "赫尔曼帝国 / 寒冷地带", img: "https://s1.imagehub.cc/images/2026/01/21/e1b9a9030f3ec51214906cc9f99167f4.jpg" },
            { id: 10, title: "大决战", location: "魔王城 / 翔龙山", img: "https://s1.imagehub.cc/images/2026/01/21/0084df2d4adcc2023a3507cc5aabea3b.jpg" }
        ];

        // 中文数字映射
        const cnNums = ["", "一", "二", "三", "四", "五", "六", "七", "八", "九", "十"];

        window.onload = function() {
            const container = document.getElementById('grid-container');

            ranceSeries.forEach((item) => {
                const card = document.createElement('div');
                card.className = 'card';

                // 仅点击卡片（非按钮区域）可以只切换背景作为预览（可选，此处点击按钮才生效）

                card.innerHTML = `
                    <div class="series-num">R${item.id}</div>
                    <img src="${item.img}" class="card-img" alt="${item.title}" loading="lazy">
                    <div class="card-info">
                        <div class="card-title">${item.title}</div>
                        <div class="card-location"><span>📍</span> ${item.location}</div>
                        <div class="start-btn" onclick="startGame(${item.id})">GAME START</div>
                    </div>
                `;
                container.appendChild(card);
            });
        };

        async function startGame(id) {
            // 1. 检查API
            if (typeof triggerSlash !== 'function' || typeof setChatMessages !== 'function') {
                alert("请在酒馆(SillyTavern)内运行以使用完整功能。");
                return;
            }

            try {
                // 2. 切换到对应的开场白 (Swipe 1-10)
                // 视觉反馈：切换页面背景和设定
                await setChatMessages([{message_id: 0, swipe_id: id}]);

                // 3. 发送开始消息
                // 获取中文数字，如 1 -> 一
                const cnNum = cnNums[id] || id;
                const message = `开始第${cnNum}章游戏`;

                // 触发发送
                triggerSlash(`/send ${message} | /trigger`);

            } catch (error) {
                console.error(error);
                alert("启动失败，请检查是否已添加对应的开场白(Swipes)。");
            }
        }
    </script>
</body>
</html>
