    width: 90%;
    animation: float 6s ease-in-out infinite;
}

@keyframes float {
    0% { transform: translateY(0px); }
    50% { transform: translateY(-10px); }
    100% { transform: translateY(0px); }
}

.cover-title {
    font-size: clamp(32px, 6vw, 56px);
    font-weight: 800;
    background: linear-gradient(135deg, #fff 0%, var(--primary-color) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    text-shadow: 0 0 20px rgba(56, 189, 248, 0.6);
    margin-bottom: 10px;
    letter-spacing: 2px;
}

.cover-subtitle {
    font-size: 18px;
    color: var(--highlight-color);
    letter-spacing: 4px;
    margin-bottom: 30px;
    text-transform: uppercase;
}

.start-btn {
    padding: 16px 48px;
    background: linear-gradient(90deg, #0ea5e9, #6366f1);
    border: none;
    border-radius: 30px;
    color: #fff;
    font-size: 18px;
    font-weight: bold;
    cursor: pointer;
    box-shadow: 0 0 20px rgba(99, 102, 241, 0.4);
    transition: all 0.3s ease;
    position: relative;
    overflow: hidden;
}

.start-btn:hover {
    transform: scale(1.05);
    box-shadow: 0 0 30px rgba(14, 165, 233, 0.6);
}

.start-btn::after {
    content: '';
    position: absolute;
    top: -50%;
    left: -50%;
    width: 200%;
    height: 200%;
    background: linear-gradient(to bottom right, rgba(255,255,255,0) 0%, rgba(255,255,255,0.1) 50%, rgba(255,255,255,0) 100%);
    transform: rotate(45deg);
    transition: all 0.3s;
    opacity: 0;
}
.start-btn:hover::after { opacity: 1; transform: rotate(45deg) translate(50%, 50%); }


/* 主界面容器 */
.container {
    width: 100%;
    max-width: 850px;
    background: var(--bg-card);
    border: 1px solid var(--border-color);
    border-radius: 16px;
    padding: 24px;
    box-shadow: 0 0 40px rgba(0, 0, 0, 0.5);
    display: none;
    min-height: 80vh;
    position: relative;
}

/* 顶部栏 */
.header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 24px;
    border-bottom: 1px solid rgba(255,255,255,0.1);
    padding-bottom: 16px;
}

.title {
    font-size: 20px;
    color: var(--primary-color);
    font-weight: 700;
    text-shadow: 0 0 10px rgba(56, 189, 248, 0.3);
}

.system-status {
    font-size: 12px;
    color: var(--highlight-color);
    background: rgba(251, 191, 36, 0.1);
    padding: 4px 8px;
    border-radius: 4px;
    border: 1px solid rgba(251, 191, 36, 0.3);
}

/* 进度条 */
.progress-container {
    width: 100%;
    height: 6px;
    background: rgba(255,255,255,0.1);
    border-radius: 3px;
    margin-bottom: 30px;
    overflow: hidden;
}
.progress-bar {
    height: 100%;
    background: linear-gradient(90deg, var(--primary-color), var(--accent-color));
    width: 0%;
    transition: width 0.4s cubic-bezier(0.4, 0, 0.2, 1);
    box-shadow: 0 0 10px var(--primary-color);
}

/* 页面切换动画 */
.page { display: none; opacity: 0; transform: translateY(20px); transition: all 0.4s ease; }
.page.active { display: block; opacity: 1; transform: translateY(0); }

/* 内容区域 */
.section-title {
    font-size: 22px;
    color: #fff;
    margin-bottom: 20px;
    display: flex;
    align-items: center;
}
.section-title::before {
    content: '';
    display: block;
    width: 4px;
    height: 24px;
    background: var(--highlight-color);
    margin-right: 12px;
    border-radius: 2px;
    box-shadow: 0 0 10px var(--highlight-color);
}

.intro-text {
    background: rgba(15, 23, 42, 0.6);
    border: 1px solid rgba(148, 163, 184, 0.2);
    border-radius: 12px;
    padding: 20px;
    max-height: 60vh;
    overflow-y: auto;
}

.intro-section { margin-bottom: 24px; }
.intro-subtitle { color: var(--primary-color); font-size: 16px; font-weight: bold; margin-bottom: 8px; }
.intro-highlight { color: var(--highlight-color); font-weight: bold; }
p { margin-bottom: 10px; line-height: 1.6; font-size: 14px; color: var(--text-dim); }

/* 表单元素 */
.custom-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 20px; }
.custom-section {
    background: rgba(255,255,255,0.03);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 12px;
    padding: 20px;
    transition: border-color 0.3s;
}
.custom-section:hover { border-color: rgba(56, 189, 248, 0.3); }

.custom-title {
    color: var(--accent-color);
    font-size: 14px;
    font-weight: bold;
    text-transform: uppercase;
    letter-spacing: 1px;
    margin-bottom: 16px;
    border-bottom: 1px solid rgba(255,255,255,0.1);
    padding-bottom: 8px;
}

.input-group { margin-bottom: 16px; }
.label { display: block; color: var(--text-dim); font-size: 12px; margin-bottom: 6px; }

.input, .textarea, select {
    width: 100%;
    background: rgba(15, 23, 42, 0.8);
    border: 1px solid #334155;
    border-radius: 8px;
    padding: 12px;
    color: #fff;
    font-size: 14px;
    transition: all 0.3s;
    font-family: inherit;
}
.input:focus, .textarea:focus, select:focus {
    outline: none;
    border-color: var(--primary-color);
    box-shadow: 0 0 0 2px rgba(56, 189, 248, 0.2);
    background: rgba(15, 23, 42, 1);
}
.textarea { min-height: 80px; resize: vertical; }

/* 按钮 */
.btn-group {
    display: flex;
    justify-content: center;
    gap: 16px;
    margin-top: 32px;
    flex-wrap: wrap;
}

.btn {
    padding: 12px 32px;
    border-radius: 8px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s;
    font-size: 14px;
    border: none;
}

.btn-primary {
    background: var(--primary-color);
    color: #0f172a;
    box-shadow: 0 4px 12px rgba(56, 189, 248, 0.3);
}
.btn-primary:hover {
    background: #7dd3fc;
    transform: translateY(-2px);
}

.btn-secondary {
    background: transparent;
    border: 1px solid #475569;
    color: var(--text-dim);
}
.btn-secondary:hover {
    border-color: var(--text-main);
    color: var(--text-main);
    background: rgba(255,255,255,0.05);
}

.btn-action {
    background: linear-gradient(135deg, var(--accent-color), #a855f7);
    color: white;
    box-shadow: 0 4px 15px rgba(168, 85, 247, 0.4);
}
.btn-action:hover {
    filter: brightness(1.1);
    transform: translateY(-2px);
}

/* 最终输出 */
.final-output {
    background: #0f172a;
    border: 1px solid #334155;
    border-radius: 12px;
    padding: 20px;
    font-family: 'Consolas', 'Monaco', monospace;
    font-size: 13px;
    color: #a5f3fc;
    line-height: 1.6;
    white-space: pre-wrap;
    max-height: 400px;
    overflow-y: auto;
    box-shadow: inset 0 0 20px rgba(0,0,0,0.5);
}

/* 滚动条美化 */
::-webkit-scrollbar { width: 8px; }
::-webkit-scrollbar-track { background: rgba(0,0,0,0.2); }
::-webkit-scrollbar-thumb { background: #475569; border-radius: 4px; }
::-webkit-scrollbar-thumb:hover { background: #64748b; }

@media (max-width: 600px) {
    .container { border-radius: 0; padding: 16px; min-height: 100vh; }
    .btn { width: 100%; }
}
</style>
</head>
<body>

    <!-- 封面 -->
    <div id="coverPage">
        <div class="cover-container">
            <div class="cover-content">
                <h1 class="cover-title">RANCE WORLD</h1>
                <p class="cover-subtitle">SYSTEM INITIALIZING...</p>
                <div style="font-size: 13px; color: var(--text-dim); margin-bottom: 30px; line-height: 1.6;">
                    正在连接至“路得拉萨乌姆”的箱庭世界<br>
                    作者 · 夜畔十二点<br>
                    <span style="color: var(--highlight-color);">你是兰斯世界中的主角兰斯，处于一个充满冒险、战争与爱欲的时代。这个世界正面临魔人军团的威胁，英雄与反派、忠诚与背叛、爱情与使命在此交织。你的故事由此展开，一起操翻兰斯大陆！</span>
                </div>
                <button class="start-btn" onclick="startCreation()">启动转生程序</button>
            </div>
        </div>
    </div>

    <!-- 主界面 -->
    <div class="container" id="mainContainer">
        <div class="header">
            <div class="title">Isekai Character Creator</div>
            <div class="system-status">● 异世界连线中</div>
        </div>

        <div class="progress-container">
            <div class="progress-bar" id="progressBar"></div>
        </div>

        <!-- 页面1：世界观 -->
        <div id="page1" class="page active">
            <h2 class="section-title">世界观档案解密</h2>
            <div class="intro-text">
                <div class="intro-section">
                    <div class="intro-subtitle">【时代背景】</div>
                    <p>大陆历<span class="intro-highlight">LP001年</span>，人类与魔人的<span class="intro-highlight">终极战争</span>即将爆发。</p>
                    <p>兰斯帝国的统治<span class="intro-highlight">岌岌可危</span>，各大势力暗中积蓄力量，未知的<span class="intro-highlight">魔人阵营</span>蓄势待发。</p>
                </div>

                <div class="intro-section">
                    <div class="intro-subtitle">【暗面势力】</div>
                    <p><span class="intro-highlight">魔人军团</span>：来自异世界的魔人种族，拥有超越凡人的力量和诡异的禁咒。它们寄宿于怨灵，融合异类，扮作人类混入各地...</p>
                    <p><span class="intro-highlight">邪教组织</span>：崇拜魔人力量的堕落者，进行非人道实验，致力于召唤更强大的魔王。</p>
                </div>

                <div class="intro-section">
                    <div class="intro-subtitle">【魔法体系】</div>
                    <p><span class="intro-highlight">人类魔法</span>：千年传承的秘术。符咒、炼金、魔阵等体系完整成熟，但能使用者稀少。</p>
                    <p><span class="intro-highlight">魔人魔法</span>：混沌而强大的禁咒力量。可扭曲现实，污染生命。更令人恐惧的是，有人类尝试融合两种魔法力量...</p>
                </div>

                <div class="intro-section">
                    <div class="intro-subtitle">【装备与力量来源】</div>
                    <p>魔晶石、魔剑、古代遗物等高阶装备散落各地。破局者“{{user}}”拥有独特天赋，可通过特殊方式<span class="intro-highlight">永久吸收他人属性</span>。</p>
                </div>

                <div class="intro-section">
                    <div class="intro-subtitle">【世界基调】</div>
                    <p>表层：帝国崩溃、魔人入侵、人类挣扎求生</p>
                    <p>暗流：禁咒肆虐、属性扭曲、权力失衡</p>
                    <p>氛围：黑暗奇幻、战争绝望、诡异压抑</p>
                </div>
            </div>
            <div class="btn-group">
                <button class="btn btn-primary" onclick="nextPage()">下一步：身份构建</button>
            </div>
        </div>

        <!-- 页面2：角色基本信息 -->
        <div id="page2" class="page">
            <h2 class="section-title">角色素体生成</h2>
            <div class="custom-grid">
                <div class="custom-section">
                    <div class="custom-title">基础信息 (必填)</div>
                    <div class="input-group">
                        <label class="label">名字</label>
                        <input type="text" id="name" class="input" placeholder="例如: 夜畔十二点">
                    </div>
                    <div class="input-group">
                        <label class="label">年龄</label>
                        <input type="text" id="age" class="input" placeholder="输入年龄（年龄18，美貌如花）">
                    </div>
                    <div class="input-group">
                        <label class="label">职业/身份</label>
                        <input type="text" id="identity" class="input" placeholder="例如: 鬼畜战士、流浪魔剑士">
                    </div>
                </div>

                <div class="custom-section">
                    <div class="custom-title">装备槽位 (选填)</div>
                    <div class="input-group">
                        <label class="label">武器</label>
                        <input type="text" id="weapon" class="input" placeholder="例如: 圣刀日光（剑灵姐姐）魔剑卡奥斯（色批大叔）">
                    </div>
                    <div class="input-group">
                        <label class="label">防具</label>
                        <input type="text" id="armor" class="input" placeholder="例如: 皇帝的新衣（裸体）">
                    </div>
                    <div class="input-group">
                        <label class="label">饰品</label>
                        <input type="text" id="accessory" class="input" placeholder="例如: 鬼畜眼镜">
                    </div>
                    <div class="input-group">
                        <label class="label">道具</label>
                        <input type="text" id="items" class="input" placeholder="例如: 蒙汗药、透视药水、乖乖水（警察叔叔就是他！）">
                    </div>
                </div>

                <div class="custom-section">
                    <div class="custom-title">技能与资产 (选填)</div>
                    <div class="input-group"><label class="label">技能 1</label><input type="text" id="skill1" class="input" placeholder="例如: 抓奶龙爪手（对女性特攻）"></div>
                    <div class="input-group"><label class="label">技能 2</label><input type="text" id="skill2" class="input" placeholder="例如: 偷窃（女性内裤）"></div>
                    <div class="input-group"><label class="label">技能 3</label><input type="text" id="skill3" class="input" placeholder="发挥你的神奇脑洞"></div>
                    <div class="input-group"><label class="label">初始资金</label><input type="text" id="money" class="input" placeholder="例如: 999999 金币富甲一方"></div>
                </div>

                <div class="custom-section">
                    <div class="custom-title">人物列传 (选填)</div>
                    <div class="input-group"><label class="label">外貌描述</label><textarea id="appearance" class="textarea" placeholder="例如: 帅过吴彦祖..."></textarea></div>
                    <div class="input-group"><label class="label">背景故事</label><textarea id="background" class="textarea" placeholder="例如: 有一个不幸的童年..."></textarea></div>
                    <div class="input-group"><label class="label">开场故事</label><textarea id="startingStory" class="textarea" placeholder="例如：被重装“大运酱”卡车送到了异世界..."></textarea></div>
                </div>
            </div>

            <div class="btn-group">
                <button class="btn btn-secondary" onclick="prevPage()">返回</button>
                <button class="btn btn-primary" onclick="nextPage()">下一步：能力分配</button>
            </div>
        </div>

        <!-- 页面3：属性分配 -->
        <div id="page3" class="page">
            <h2 class="section-title">能力值作弊修改 (Cheat Mode)</h2>
            <p style="color: var(--highlight-color); margin-bottom: 20px;">提示：作为被选中的主角，你可以随意定义数值和描述。</p>

            <div class="custom-section" style="margin-bottom: 20px;">
                <label class="label">初始等级评估:</label>
                <select id="levelSelect">
                    <option value="1">LV 10 - 一般人</option>
                    <option value="2">LV 20 - 天才</option>
                    <option value="3">LV 30 - 精英 (人类极限)</option>
                    <option value="4">LV 40 - 英杰</option>
                    <option value="5">LV 50 - 传奇</option>
                    <option value="6">LV 99 - 限界突破</option>
                </select>
            </div>

            <div class="custom-grid">
                <div class="custom-section">
                    <div class="custom-title">ATK (攻击力)</div>
                    <input type="text" id="stat_atk" class="input" placeholder="例如: 9999 (一拳超人)" />
                </div>

                <div class="custom-section">
                    <div class="custom-title">DEF (防御力)</div>
                    <input type="text" id="stat_def" class="input" placeholder="例如: 9999 (绝对防御)" />
                </div>

                <div class="custom-section">
                    <div class="custom-title">SPD (速度)</div>
                    <input type="text" id="stat_spd" class="input" placeholder="例如: 9999 (走路就撞墙)" />
                </div>

                <div class="custom-section">
                    <div class="custom-title">INT (魔力/智力)</div>
                    <input type="text" id="stat_int" class="input" placeholder="例如: 0 (智障战士)" />
                </div>

                <div class="custom-section">
                    <div class="custom-title">LUK (运势)</div>
                    <input type="text" id="stat_luk" class="input" placeholder="例如: 9999 (无敌幸运的LSP)" />
                </div>
            </div>

            <div class="btn-group">
                <button class="btn btn-secondary" onclick="prevPage()">返回</button>
                <button class="btn btn-primary" onclick="generateCharacter()">生成角色卡</button>
            </div>
        </div>

        <!-- 页面4：最终输出 -->
        <div id="page4" class="page">
            <h2 class="section-title">角色数据封装完毕</h2>
            <div style="text-align: center; margin-bottom: 20px; color: var(--text-dim);">
                <p>系统已准备就绪，点击下方紫色按钮可直接将数据发送至终端。</p>
            </div>

            <div class="final-output" id="finalOutput"></div>

            <div class="btn-group">
                <button class="btn btn-secondary" onclick="location.reload()">重新创建</button>
                <button class="btn btn-primary" onclick="copyToClipboard()">复制数据</button>
                <button class="btn btn-action" onclick="sendToChat()">发送给AI并开始 &gt;</button>
            </div>
        </div>
    </div>

    <script>
        // 页面导航逻辑
        let currentPage = 1;
        const totalPages = 4;

        function startCreation() {
            const cover = document.getElementById('coverPage');
            cover.style.opacity = '0';
            cover.style.pointerEvents = 'none';
            setTimeout(() => {
                document.getElementById('mainContainer').style.display = 'block';
                showPage(1);
            }, 500);
        }

        function showPage(pageNum) {
            document.querySelectorAll('.page').forEach(el => el.classList.remove('active'));
            document.getElementById('page' + pageNum).classList.add('active');
            currentPage = pageNum;
            updateProgress();
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }

        function nextPage() {
            if(currentPage < totalPages) showPage(currentPage + 1);
        }
        function prevPage() {
            if(currentPage > 1) showPage(currentPage - 1);
        }

        function updateProgress() {
            const percent = ((currentPage - 1) / (totalPages - 1)) * 100;
            document.getElementById('progressBar').style.width = percent + '%';
        }

        // 收集数据并生成文本
        function generateCharacter() {
            // 获取基本信息
            const name = document.getElementById('name').value || "无名氏";
            const age = document.getElementById('age').value || "未知";
            const identity = document.getElementById('identity').value || "流浪者";

            // 获取装备
            const weapon = document.getElementById('weapon').value || "空手";
            const armor = document.getElementById('armor').value || "布衣";
            const accessory = document.getElementById('accessory').value || "无";
            const items = document.getElementById('items').value || "无";

            // 获取技能金钱
            const skill1 = document.getElementById('skill1').value || "—";
            const skill2 = document.getElementById('skill2').value || "—";
            const skill3 = document.getElementById('skill3').value || "—";
            const money = document.getElementById('money').value || "0 G";

            // 获取描述
            const appearance = document.getElementById('appearance').value || "无描述";
            const background = document.getElementById('background').value || "无背景";
            const startStory = document.getElementById('startingStory').value || "第十一章";

            // 获取等级和属性
            const levelSelect = document.getElementById('levelSelect');
            const levelText = levelSelect.options[levelSelect.selectedIndex].text;

            const atk = document.getElementById('stat_atk').value || "10";
            const def = document.getElementById('stat_def').value || "10";
            const spd = document.getElementById('stat_spd').value || "10";
            const intVal = document.getElementById('stat_int').value || "10";
            const luk = document.getElementById('stat_luk').value || "10";

            // 组装文本
            const outputText =
`【兰斯世界第十一章自定义角色卡，开始第十一章冒险！】
━━━━━━━━━━━━━━━━━━
【基础情报】
名字: ${name}
年龄: ${age}
身份: ${identity}
等级: ${levelText}

【六维参数】 (Cheat)
ATK: ${atk}
DEF: ${def}
SPD: ${spd}
INT: ${intVal}
LUK: ${luk}

【装备资产】
武器: ${weapon}
防具: ${armor}
饰品: ${accessory}
持有物: ${items}
所持金: ${money}

【技能表】
[1] ${skill1}
[2] ${skill2}
[3] ${skill3}

【人物档案】
[外貌]
${appearance}

[背景]
${background}

[开场]
${startStory}
━━━━━━━━━━━━━━━━━━`;

            document.getElementById('finalOutput').textContent = outputText;
            nextPage(); // 跳转到最终页
        }

        // 复制功能
        function copyToClipboard() {
            const text = document.getElementById('finalOutput').textContent;
            navigator.clipboard.writeText(text).then(() => {
                alert("已复制到剪贴板！");
            }).catch(err => {
                // 兼容性处理
                const ta = document.createElement("textarea");
                ta.value = text;
                document.body.appendChild(ta);
                ta.select();
                document.execCommand("copy");
                document.body.removeChild(ta);
                alert("已复制到剪贴板！");
            });
        }

        // 自动发送功能
        function sendToChat() {
