<body>
    <div class="audio-player-container">
        <!-- 播放按钮 -->
        <button class="play-button" id="play-button" title="播放/暂停">▶</button>

        <!-- 进度条 -->
        <div class="progress-container" id="progress-bar">
            <div class="progress-fill" id="progress-fill"></div>
        </div>

        <!-- 时间显示 -->
        <span class="time-display" id="time-display">0:00</span>

        <!-- 音频信息（默认隐藏）-->
        <!-- $1 将被正则表达式替换为音频描述文本 -->
        <span class="audio-info" id="audio-title">$1</span>

        <!-- 音量控制（悬停显示）-->
        <div class="volume-container">
            <span class="volume-icon" id="volume-icon" title="音量">🔊</span>
            <input type="range" class="volume-slider" id="volume-slider" min="0" max="100" value="80">
        </div>

        <!-- 音频元素 -->
        <!-- $2 将被正则表达式替换为音频文件名（如 Ab3xY9.mp3） -->
        <audio id="audio-element" preload="auto" autoplay>
            <source src="https://files.catbox.moe/$2" type="audio/mpeg">
        </audio>
    </div>

    <script>
        // ========== DOM 元素 ==========
        const audio = document.getElementById('audio-element');
        const playButton = document.getElementById('play-button');
        const progressBar = document.getElementById('progress-bar');
        const progressFill = document.getElementById('progress-fill');
        const timeDisplay = document.getElementById('time-display');
        const volumeSlider = document.getElementById('volume-slider');
        const volumeIcon = document.getElementById('volume-icon');

        // ========== 初始化音量 ==========
        const savedVolume = localStorage.getItem('audioVolume') || '80';
        volumeSlider.value = savedVolume;
        audio.volume = savedVolume / 100;

        // ========== 格式化时间 ==========
        function formatTime(seconds) {
            if (isNaN(seconds)) return '0:00';
            const mins = Math.floor(seconds / 60);
            const secs = Math.floor(seconds % 60);
            return `${mins}:${secs.toString().padStart(2, '0')}`;
        }

        // ========== 播放控制 ==========
        playButton.addEventListener('click', () => {
            if (audio.paused) {
                audio.play().catch(err => console.error('播放失败:', err));
            } else {
                audio.pause();
            }
        });

        audio.addEventListener('play', () => {
            playButton.textContent = '⏸';
        });

        audio.addEventListener('pause', () => {
            playButton.textContent = '▶';
        });

        // ========== 音量控制（核心功能）==========
        volumeSlider.addEventListener('input', (e) => {
            const volume = e.target.value / 100;
            audio.volume = volume;
            localStorage.setItem('audioVolume', e.target.value);

            // 更新音量图标
            if (volume === 0) {
                volumeIcon.textContent = '🔇';
            } else if (volume < 0.5) {
                volumeIcon.textContent = '🔉';
            } else {
                volumeIcon.textContent = '🔊';
            }
        });

        // 点击音量图标静音/取消静音
        volumeIcon.addEventListener('click', () => {
            if (audio.volume > 0) {
                audio.dataset.prevVolume = audio.volume;
                audio.volume = 0;
                volumeSlider.value = 0;
                volumeIcon.textContent = '🔇';
            } else {
                const prevVolume = audio.dataset.prevVolume || 0.8;
                audio.volume = prevVolume;
                volumeSlider.value = prevVolume * 100;
                volumeIcon.textContent = '🔊';
            }
        });

        // ========== 进度条 ==========
        audio.addEventListener('timeupdate', () => {
            if (audio.duration) {
                const progress = (audio.currentTime / audio.duration) * 100;
                progressFill.style.width = `${progress}%`;
                timeDisplay.textContent = formatTime(audio.currentTime);
            }
        });

        progressBar.addEventListener('click', (e) => {
            const rect = progressBar.getBoundingClientRect();
            const clickX = e.clientX - rect.left;
            const percentage = clickX / rect.width;
            audio.currentTime = percentage * audio.duration;
        });

        // ========== 播放结束 ==========
        audio.addEventListener('ended', () => {
            playButton.textContent = '▶';
            progressFill.style.width = '0%';
            audio.currentTime = 0;
        });

        // ========== 错误处理 ==========
        audio.addEventListener('error', () => {
            playButton.textContent = '✖';
            playButton.style.background = '#ff4444';
        });

        // ========== 自动播放 ==========
        audio.play().catch(() => {
            playButton.textContent = '▶';
        });
    </script>
</body>
</html>
